class User:
    def __init__(self, username):
        self.username = username

class Resource:
    def __init__(self, name, owner):
        self.name = name
        self.owner = owner
        self.permissions = {}  # {username: ['read', 'write']}
        self.permissions[owner.username] = ['read', 'write', 'delete']

    def grant_permission(self, user, access_type):
        """Owner grants permission to a user"""
        if user.username not in self.permissions:
            self.permissions[user.username] = []
        if access_type not in self.permissions[user.username]:
            self.permissions[user.username].append(access_type)
        print(f"Granted {access_type} permission to {user.username} on {self.name}")

    def revoke_permission(self, user, access_type):
        """Owner revokes permission from a user"""
        if user.username in self.permissions:
            if access_type in self.permissions[user.username]:
                self.permissions[user.username].remove(access_type)
                print(f"Revoked {access_type} permission from {user.username}")

    def check_access(self, user, access_type):
        """Check if user has specific access"""
        if user.username in self.permissions:
            return access_type in self.permissions[user.username]
        return False

# Demo
alice = User("Alice")
bob = User("Bob")
charlie = User("Charlie")

# Alice creates a document (she is the owner)
document = Resource("Project_Report.txt", alice)

# Alice grants Bob read access
document.grant_permission(bob, "read")

# Alice grants Charlie read and write access
document.grant_permission(charlie, "read")
document.grant_permission(charlie, "write")

# Access checks
print(f"\nBob can read: {document.check_access(bob, 'read')}")
print(f"Bob can write: {document.check_access(bob, 'write')}")
print(f"Charlie can read: {document.check_access(charlie, 'read')}")
print(f"Charlie can write: {document.check_access(charlie, 'write')}")
